// Transform BCC feedback emails to the feedback staging schema.
// These are copies of emails the professor sent, captured via BCC.
// The Python feedback_handler.py will process them from staging/feedback/.

const items = [];

for (const item of $input.all()) {
  const msg = item.json;

  const headers = {};
  for (const h of (msg.payload?.headers || [])) {
    headers[h.name.toLowerCase()] = h.value;
  }

  function extractBody(payload) {
    if (payload.mimeType === 'text/plain' && payload.body?.data) {
      return Buffer.from(payload.body.data, 'base64').toString('utf-8');
    }
    for (const part of (payload.parts || [])) {
      const text = extractBody(part);
      if (text) return text;
    }
    return '';
  }

  const feedback = {
    // Source email metadata
    id: msg.id,
    thread_id: msg.threadId,
    subject: headers['subject'] || '(no subject)',
    from: headers['from'] || '',
    to: headers['to'] || '',
    date: headers['date'] || '',
    snippet: msg.snippet || '',
    body_text: extractBody(msg.payload || '').substring(0, 3000),
    labels: msg.labelIds || [],
    attachments: [],
    // Mark as feedback so Python knows how to process it
    _feedback_type: 'bcc_sent_copy'
  };

  items.push({ json: feedback });
}

return items;
